import PostCard from "../components/PostCard";

function Home() {

  const posts = [
    {
      id:1,
      title:"MERN Stack Guide",
      content:"Learn MERN from scratch",
      author:"Kavya",
      likes:12,
      comments:5
    },
    {
      id:2,
      title:"React Tutorial",
      content:"Build modern UI easily",
      author:"Admin",
      likes:8,
      comments:3
    }
  ];

  return (
    <div className="container">
      <h1>Latest Blog Posts</h1>

      {posts.map(post => (
        <PostCard
          key={post.id}
          post={post}
        />
      ))}
    </div>
  );
}

export default Home;
